  4 /// Events emitted while preparing a manual install: progress while bytes are
  5 /// being downloaded, then a single `verifying` and `extracting` notification.
  6 public enum UpdateDownloadEvent: Sendable, Equatable {
  7     case progress(receivedBytes: Int64, totalBytes: Int64?)
  8     case verifying
  9     case extracting
 10 }
 11 
 12 public typealias UpdateDownloadEventHandler = @Sendable (UpdateDownloadEvent) -> Void
 13 
 14 public enum UpdateDownloaderError: Error, Equatable {
 15     case downloadFailed(message: String)
 16     case unexpectedHTTPStatus(code: Int)
 17     case shaDownloadFailed(message: String)
 18     case shaParseFailed(raw: String)
 19     case shaMismatch(expected: String, actual: String)
 20     case extractionFailed(message: String)
 21     case noAppBundleInArchive
 22     case fileSystemError(message: String)
 23 }
