 25 /// Downloads a release zip with progress callbacks, verifies its SHA256, then
 26 /// extracts the contained `.app` bundle into a staging directory. The staged
 27 /// path is returned so the caller can swap it into place via the finalize
 28 /// script after the user confirms the restart.
 29 public actor UpdateDownloader {
 30     private let sessionConfiguration: URLSessionConfiguration
 31     private let stagingRoot: URL
 32     private let process: ProcessRunning
 33     private let fileManager: FileManager
 34     private let logger: FileLogger
 35     private let dittoPath: String
 36 
 37     public init(
 38         sessionConfiguration: URLSessionConfiguration = .default,
 39         stagingRoot: URL? = nil,
 40         process: ProcessRunning = FoundationProcessRunner(),
 41         fileManager: FileManager = .default,
 42         logger: FileLogger = Loggers.app,
 43         dittoPath: String = "/usr/bin/ditto"
 44     ) {
 45         self.sessionConfiguration = sessionConfiguration
 46         self.stagingRoot = stagingRoot ?? UpdateInstaller.defaultStagingDirectory()
 47         self.process = process
 48         self.fileManager = fileManager
 49         self.logger = logger
 50         self.dittoPath = dittoPath
 51     }
 52 
 53     /// Downloads the release zip, verifies its SHA256 (when available), extracts
 54     /// it, and returns the path to the staged `.app` bundle ready to swap in.
 55     public func downloadAndStage(
 56         update: AvailableUpdate,
 57         onEvent: @escaping UpdateDownloadEventHandler
 58     ) async throws -> URL {
 59         let workDir = stagingRoot.appendingPathComponent(update.version.rawValue, isDirectory: true)
 60         // Start clean: a previous failed attempt may have left half-extracted state.
 61         try? fileManager.removeItem(at: workDir)
 62         do {
 63             try fileManager.createDirectory(at: workDir, withIntermediateDirectories: true)
 64         } catch {
 65             throw UpdateDownloaderError.fileSystemError(message: "create staging dir: \(error)")
 66         }
 67 
 68         let zipURL = workDir.appendingPathComponent("release.zip")
 69         try await downloadFile(from: update.downloadURL, to: zipURL, onEvent: onEvent)
 70 
 71         if let shaURL = update.sha256URL {
 72             onEvent(.verifying)
 73             try await verifySHA256(file: zipURL, expectedFrom: shaURL, workDir: workDir)
 74         }
 75 
 76         onEvent(.extracting)
 77         let extractedDir = workDir.appendingPathComponent("extracted", isDirectory: true)
 78         try? fileManager.removeItem(at: extractedDir)
 79         try fileManager.createDirectory(at: extractedDir, withIntermediateDirectories: true)
 80         try await extractZip(zipURL: zipURL, into: extractedDir)
 81 
 82         guard let stagedApp = try findAppBundle(in: extractedDir) else {
 83             throw UpdateDownloaderError.noAppBundleInArchive
 84         }
 85         logger.log(.info, "Update staged at \(stagedApp.path)")
 86         return stagedApp
 87     }
 88 
 89     // MARK: - Download
 90 
 91     private func downloadFile(
 92         from url: URL,
 93         to destination: URL,
 94         onEvent: @escaping UpdateDownloadEventHandler
 95     ) async throws {
 96         let observer = DownloadObserver(onEvent: onEvent)
 97         let session = URLSession(configuration: sessionConfiguration, delegate: observer, delegateQueue: nil)
 98         defer { session.invalidateAndCancel() }
 99 
100         let tempURL: URL
101         do {
102             tempURL = try await observer.runDownload(session: session, url: url)
103         } catch let error as UpdateDownloaderError {
104             throw error
105         } catch {
106             throw UpdateDownloaderError.downloadFailed(message: String(describing: error))
107         }
108 
109         // The system removes the temp file once the delegate returns, so the
110         // observer already moved it to a stable path; here we just rename it
111         // into the destination atomically.
112         try? fileManager.removeItem(at: destination)
113         do {
114             try fileManager.moveItem(at: tempURL, to: destination)
115         } catch {
116             throw UpdateDownloaderError.fileSystemError(message: "move downloaded zip: \(error)")
117         }
118     }
119 
120     // MARK: - SHA256
121 
122     private func verifySHA256(file: URL, expectedFrom shaURL: URL, workDir: URL) async throws {
123         let data: Data
124         do {
125             let (raw, response) = try await URLSession(configuration: sessionConfiguration).data(from: shaURL)
126             if let http = response as? HTTPURLResponse, http.statusCode != 200 {
127                 throw UpdateDownloaderError.unexpectedHTTPStatus(code: http.statusCode)
128             }
129             data = raw
130         } catch let error as UpdateDownloaderError {
131             throw error
132         } catch {
133             throw UpdateDownloaderError.shaDownloadFailed(message: String(describing: error))
134         }
135         let raw = String(decoding: data, as: UTF8.self)
136             .trimmingCharacters(in: .whitespacesAndNewlines)
137         // Format is typically "<hex>  filename" or just "<hex>".
138         guard let firstToken = raw.split(whereSeparator: { $0.isWhitespace }).first else {
139             throw UpdateDownloaderError.shaParseFailed(raw: raw)
140         }
141         let expected = String(firstToken).lowercased()
142         guard expected.allSatisfy({ $0.isHexDigit }), expected.count == 64 else {
143             throw UpdateDownloaderError.shaParseFailed(raw: raw)
144         }
145         let actual = try sha256Hex(of: file)
146         guard actual.lowercased() == expected else {
147             throw UpdateDownloaderError.shaMismatch(expected: expected, actual: actual)
148         }
149     }
150 
151     private func sha256Hex(of fileURL: URL) throws -> String {
152         let handle: FileHandle
153         do {
154             handle = try FileHandle(forReadingFrom: fileURL)
155         } catch {
156             throw UpdateDownloaderError.fileSystemError(message: "open zip for hashing: \(error)")
157         }
158         defer { try? handle.close() }
159         var hasher = SHA256()
160         // 1 MiB chunks: large enough to amortize syscalls, small enough to keep
161         // the resident set in check on large zips.
162         let chunkSize = 1 * 1024 * 1024
163         while true {
164             let chunk = handle.readData(ofLength: chunkSize)
165             if chunk.isEmpty { break }
166             hasher.update(data: chunk)
167         }
168         let digest = hasher.finalize()
169         return digest.map { String(format: "%02x", $0) }.joined()
170     }
