172     // MARK: - Extract
173 
174     private func extractZip(zipURL: URL, into destDir: URL) async throws {
175         let result: ProcessExecutionResult
176         do {
177             result = try await process.run(
178                 executablePath: dittoPath,
179                 arguments: ["-x", "-k", zipURL.path, destDir.path],
180                 timeoutSeconds: 120
181             )
182         } catch {
183             throw UpdateDownloaderError.extractionFailed(message: String(describing: error))
184         }
185         guard !result.timedOut, result.terminationStatus == 0 else {
186             throw UpdateDownloaderError.extractionFailed(
187                 message: "ditto exit=\(result.terminationStatus) timedOut=\(result.timedOut)"
188             )
189         }
190     }
191 
192     private func findAppBundle(in directory: URL) throws -> URL? {
193         // The zip layout is `<archive root>/AI Usages Tracker.app`, but be
194         // tolerant of a single nested wrapper directory in case the build
195         // pipeline ever changes.
196         let directContents: [URL]
197         do {
198             directContents = try fileManager.contentsOfDirectory(
199                 at: directory,
200                 includingPropertiesForKeys: [.isDirectoryKey],
201                 options: [.skipsHiddenFiles]
202             )
203         } catch {
204             throw UpdateDownloaderError.fileSystemError(message: "list extracted dir: \(error)")
205         }
206         if let app = directContents.first(where: { $0.pathExtension == "app" }) {
207             return app
208         }
209         for child in directContents where (try? child.resourceValues(forKeys: [.isDirectoryKey]).isDirectory) == true {
210             let nested = try fileManager.contentsOfDirectory(at: child, includingPropertiesForKeys: nil)
211             if let app = nested.first(where: { $0.pathExtension == "app" }) {
212                 return app
213             }
214         }
215         return nil
216     }
217 }
