219 // MARK: - Download observer
220 
221 /// Bridges URLSession's delegate-based download progress callbacks to the
222 /// async/await world while keeping the staged temp file alive past the
223 /// delegate's `didFinishDownloadingTo` call (the system deletes the original
224 /// shortly after that callback returns).
225 // swiftlint:disable:next w4_unchecked_sendable — internal-only helper, all mutable state guarded by `lock`
226 private final class DownloadObserver: NSObject, URLSessionDownloadDelegate, @unchecked Sendable {
227     private let onEvent: UpdateDownloadEventHandler
228     private let lock = NSLock()
229     private var continuation: CheckedContinuation<URL, Error>?
230     private var resumed = false
231     private var stableURL: URL?
232 
233     init(onEvent: @escaping UpdateDownloadEventHandler) {
234         self.onEvent = onEvent
235         super.init()
236     }
237 
238     func runDownload(session: URLSession, url: URL) async throws -> URL {
239         try await withCheckedThrowingContinuation { (cont: CheckedContinuation<URL, Error>) in
240             self.continuation = cont
241             let task = session.downloadTask(with: url)
242             task.resume()
243         }
244     }
245 
246     func urlSession(
247         _ session: URLSession,
248         downloadTask: URLSessionDownloadTask,
249         didWriteData bytesWritten: Int64,
250         totalBytesWritten: Int64,
251         totalBytesExpectedToWrite: Int64
252     ) {
253         let total: Int64? = totalBytesExpectedToWrite > 0 ? totalBytesExpectedToWrite : nil
254         onEvent(.progress(receivedBytes: totalBytesWritten, totalBytes: total))
255     }
256 
257     func urlSession(
258         _ session: URLSession,
259         downloadTask: URLSessionDownloadTask,
260         didFinishDownloadingTo location: URL
261     ) {
262         // URLSession returns a temp file that gets deleted as soon as the
263         // delegate method returns, so we must move it synchronously here.
264         let stable = FileManager.default.temporaryDirectory
265             .appendingPathComponent("ai-tracker-dl-\(UUID().uuidString).zip")
266         do {
267             try FileManager.default.moveItem(at: location, to: stable)
268         } catch {
269             resume(.failure(UpdateDownloaderError.fileSystemError(message: "stage download: \(error)")))
270             return
271         }
272         lock.lock()
273         stableURL = stable
274         lock.unlock()
275 
276         if let http = downloadTask.response as? HTTPURLResponse, !(200...299).contains(http.statusCode) {
277             try? FileManager.default.removeItem(at: stable)
278             resume(.failure(UpdateDownloaderError.unexpectedHTTPStatus(code: http.statusCode)))
279             return
280         }
281         resume(.success(stable))
282     }
283 
284     func urlSession(_ session: URLSession, task: URLSessionTask, didCompleteWithError error: Error?) {
285         if let error {
286             resume(.failure(UpdateDownloaderError.downloadFailed(message: String(describing: error))))
287         }
288         // Success path is handled in didFinishDownloadingTo; no-op here.
289     }
290 
291     private func resume(_ result: Result<URL, Error>) {
292         lock.lock()
293         guard !resumed, let cont = continuation else { lock.unlock(); return }
294         resumed = true
295         continuation = nil
296         lock.unlock()
297         switch result {
298         case .success(let url): cont.resume(returning: url)
299         case .failure(let err): cont.resume(throwing: err)
300         }
301     }
302 }

